  return `${`bg-${props.variant}-50 text-${props.variant}-700`}`
});
</script>


<template>
  <div
    class="py-0.5 px-2 space-x-1 w-fit flex items-center text-xs rounded-full cursor-default select-none transition-all"
    :class="bgColor"
  >
    <slot name="prefix"/>
    <p>{{ label }}</p>
    <slot name="suffix"/>
  </div>

</template>

